#!/bin/bash
set -euo pipefail

INBOX_DIR="${INBOX_DIR:-/mnt/videos/inbox}"
TMP_DIR_BASE="${TMP_DIR_BASE:-/mnt/tmp/video_pipeline}"
R2_BUCKET="${R2_BUCKET:-vmp-videos}"
MP3_NAME="podcast.mp3"
MP3_PREVIEW_NAME="podcast_preview.mp3"
# Optional RSS preview: `podcast_preview.mp3` — generated by webhook (see packages/podcast-host/supervisor.mjs) or `render_podcast_preview_mp3.sh`.
BACKFILL_FROM_R2="${BACKFILL_FROM_R2:-1}"
MP3_ONLY="${MP3_ONLY:-0}"
PREVIEW_MP3_SECONDS="${PREVIEW_MP3_SECONDS:-180}"
PREVIEW_MP3_LOCK_SECONDS="${PREVIEW_MP3_LOCK_SECONDS:-60}"
PREVIEW_MP3_ENABLED="${PREVIEW_MP3_ENABLED:-1}"

MAX_JOBS=2

mkdir -p "$TMP_DIR_BASE"
SLOT_DIR="$TMP_DIR_BASE/.slots"
SLOT_LOCK="$TMP_DIR_BASE/.slots.lock"
BACKFILL_STAGING_DIR="$TMP_DIR_BASE/.backfill_staging"
mkdir -p "$SLOT_DIR"
mkdir -p "$BACKFILL_STAGING_DIR"
touch "$SLOT_LOCK"

log() {
    echo "$(date '+%F %T') $*"
}

emit_pipeline_event() {
    local video_id="$1"
    local stage="$2"
    local status="$3"
    local detail="${4:-}"
    printf 'VMP_PIPELINE_EVENT\t%s\t%s\t%s\t%s\n' "$video_id" "$stage" "$status" "$detail"
}

wait_for_slot() {
    local holder_pid="${1:-$BASHPID}"
    while true; do
        if flock -x "$SLOT_LOCK" bash -s -- "$SLOT_DIR" "$MAX_JOBS" "$holder_pid" <<'EOF'
set -euo pipefail
slot_dir="$1"
max_jobs="$2"
holder_pid="$3"

mkdir -p "$slot_dir"
shopt -s nullglob
files=( "$slot_dir"/*.pid )

for token in "${files[@]}"; do
    pid="$(basename "$token" .pid)"
    kill -0 "$pid" 2>/dev/null || rm -f "$token"
done

files=( "$slot_dir"/*.pid )
current_jobs=${#files[@]}
if [ "$current_jobs" -lt "$max_jobs" ]; then
    printf "%s\n" "$holder_pid" > "$slot_dir/$holder_pid.pid"
    exit 0
fi
exit 1
EOF
        then
            return
        fi
        sleep 1
    done
}

release_slot() {
    local holder_pid="${1:-$BASHPID}"
    rm -f "$SLOT_DIR/$holder_pid.pid"
}

has_remote_file() {
    local video_id="$1"
    local file_name="$2"
    rclone lsf "${R2_BUCKET}:/videos/${video_id}" --recursive 2>/dev/null | awk -F/ '{print $NF}' | grep -qx "$file_name"
}

has_remote_hls_complete() {
    local video_id="$1"
    local remote
    if ! remote=$(rclone lsf "${R2_BUCKET}:/videos/${video_id}" --recursive 2>/dev/null); then
        return 1
    fi

    local basenames
    basenames=$(echo "$remote" | awk -F/ '{print $NF}')

    echo "$basenames" | grep -qx "master.m3u8" || return 1

    for res in 1080 720 480; do
        echo "$basenames" | grep -qx "init_${res}.mp4" || return 1
        local cnt
        cnt=$(echo "$basenames" | grep -c "^seg_${res}_.*\\.m4s$" || true)
        [ "${cnt:-0}" -gt 0 ] || return 1
    done

    return 0
}

find_remote_source_key() {
    local video_id="$1"
    local key
    key=$(rclone lsf "${R2_BUCKET}:/videos/${video_id}/source" 2>/dev/null | \
        grep -Ei '\.(mp4|mkv|mov)$' | head -n 1 || true)
    [ -n "$key" ] || return 1
    printf "%s\n" "$key"
}

ensure_input_from_r2() {
    local video_id="$1"
    local input_path="$2"
    local src_key

    src_key=$(find_remote_source_key "$video_id" || true)
    if [ -z "$src_key" ]; then
        log "❌ $video_id has no source file in R2 (videos/$video_id/source/)"
        return 1
    fi

    mkdir -p "$(dirname "$input_path")"
    log "☁️  Downloading source from R2 for $video_id ($src_key)"
    rclone copyto "${R2_BUCKET}:/videos/${video_id}/source/${src_key}" "$input_path"
}

process_video() {
    VIDEO_ID="$1"
    INPUT_PATH="$2"
    SOURCE="${3:-watchfolder}"
    TMP_DIR="$TMP_DIR_BASE/$VIDEO_ID"

    mkdir -p "$TMP_DIR"
    emit_pipeline_event "$VIDEO_ID" "detected" "active" "source=${SOURCE}"

    LOCK="$TMP_DIR/.lock"
    DONE="$TMP_DIR/.done"

    if [ -f "$DONE" ]; then
        log "✅ $VIDEO_ID already done"
        emit_pipeline_event "$VIDEO_ID" "done" "success" "already_done"
        return
    fi

    if [ -f "$LOCK" ]; then
        if ! pgrep -f "process_video.*$VIDEO_ID" > /dev/null; then
            log "⚠️ Stale lock detected for $VIDEO_ID — recovering"
            rm -f "$LOCK"
        else
            log "⏩ $VIDEO_ID already processing"
            emit_pipeline_event "$VIDEO_ID" "deduped" "active" "already_processing"
            return
        fi
    fi

    touch "$LOCK"
    wait_for_slot "$BASHPID"

    on_process_error() {
        log "❌ Error occurred for $VIDEO_ID — releasing lock"
        emit_pipeline_event "$VIDEO_ID" "failed" "failed" "pipeline_error"
        rm -f "$LOCK"
        release_slot "$BASHPID"
    }
    trap on_process_error ERR

    log "📥 Processing $VIDEO_ID"
    emit_pipeline_event "$VIDEO_ID" "wait_upload_complete" "active" "waiting_for_file_stability"

    if [ ! -f "$INPUT_PATH" ]; then
        if ! ensure_input_from_r2 "$VIDEO_ID" "$INPUT_PATH"; then
            emit_pipeline_event "$VIDEO_ID" "failed" "failed" "missing_source_in_r2"
            rm -f "$LOCK"
            rm -f "$BACKFILL_STAGING_DIR/${VIDEO_ID}.mp4"
            release_slot "$BASHPID"
            garbage_collect
            return
        fi
    fi

    PREV=-1
    while true; do
        [ ! -f "$INPUT_PATH" ] && { log "❌ Missing input"; rm -f "$LOCK"; release_slot "$BASHPID"; return; }
        CUR=$(stat -c%s "$INPUT_PATH")
        [[ "$CUR" -eq "$PREV" ]] && break
        PREV=$CUR
        sleep 2
    done

    log "✅ Upload complete"
    emit_pipeline_event "$VIDEO_ID" "wait_upload_complete" "active" "stable"
    emit_pipeline_event "$VIDEO_ID" "probe" "active" "probing_streams"

    HAS_AUDIO=$({
        ffprobe -v error -select_streams a \
            -show_entries stream=index -of csv=p=0 "$INPUT_PATH" 2>/dev/null || true
    } | wc -l)
    HAS_AUDIO=${HAS_AUDIO:-0}

    should_process_video="1"
    if [ "$MP3_ONLY" = "1" ] || has_remote_hls_complete "$VIDEO_ID"; then
        should_process_video="0"
    fi

    if [ "$should_process_video" = "1" ]; then
        need_encode=false
        for r in 1080p.mp4 720p.mp4 480p.mp4; do
            if [ -f "$TMP_DIR/$r" ]; then
                if ! ffprobe -v error -show_streams "$TMP_DIR/$r" >/dev/null 2>&1; then
                    log "⚠️ Existing $r is corrupt, will re-encode"
                    rm -f "$TMP_DIR/$r"
                    need_encode=true
                fi
            else
                need_encode=true
            fi
        done

        if [ "$need_encode" = true ]; then
            log "🚀 Encoding missing renditions"
            emit_pipeline_event "$VIDEO_ID" "encode" "active" "start"

            emit_pipeline_event "$VIDEO_ID" "encode" "active" "1/3 1080p"
            ffmpeg -hide_banner -y -i "$INPUT_PATH" \
                -vf "scale=1920:1080:force_original_aspect_ratio=decrease:force_divisible_by=2" \
                -map 0:v:0 -map 0:a? -c:v libx264 -b:v 5M -preset fast -c:a aac -b:a 128k -f mp4 "$TMP_DIR/1080p.mp4.tmp.$$"
            mv "$TMP_DIR/1080p.mp4.tmp.$$" "$TMP_DIR/1080p.mp4"
            emit_pipeline_event "$VIDEO_ID" "encode" "active" "2/3 720p"
            ffmpeg -hide_banner -y -i "$INPUT_PATH" \
                -vf "scale=1280:720:force_original_aspect_ratio=decrease:force_divisible_by=2" \
                -map 0:v:0 -map 0:a? -c:v libx264 -b:v 3M -preset fast -c:a aac -b:a 128k -f mp4 "$TMP_DIR/720p.mp4.tmp.$$"
            mv "$TMP_DIR/720p.mp4.tmp.$$" "$TMP_DIR/720p.mp4"
            emit_pipeline_event "$VIDEO_ID" "encode" "active" "3/3 480p"
            ffmpeg -hide_banner -y -i "$INPUT_PATH" \
                -vf "scale=854:480:force_original_aspect_ratio=decrease:force_divisible_by=2" \
                -map 0:v:0 -map 0:a? -c:v libx264 -b:v 1.5M -preset fast -c:a aac -b:a 96k -f mp4 "$TMP_DIR/480p.mp4.tmp.$$"
            mv "$TMP_DIR/480p.mp4.tmp.$$" "$TMP_DIR/480p.mp4"

            log "✅ Encoding done"
            emit_pipeline_event "$VIDEO_ID" "encode" "active" "done"
        else
            log "⏩ Skipping encoding (already done)"
            emit_pipeline_event "$VIDEO_ID" "encode" "active" "skipped_existing"
        fi
    else
        if [ "$MP3_ONLY" = "1" ]; then
            log "⏩ MP3_ONLY=1 — skipping video encoding and packaging"
            emit_pipeline_event "$VIDEO_ID" "encode" "active" "skipped_mp3_only"
        else
            log "⏩ Remote HLS already complete for $VIDEO_ID — skipping video encoding and packaging"
            emit_pipeline_event "$VIDEO_ID" "encode" "active" "skipped_remote_hls_complete"
        fi
    fi

    need_mp3=true
    if [ -f "$TMP_DIR/$MP3_NAME" ]; then
        if [ -s "$TMP_DIR/$MP3_NAME" ] && ffprobe -v error -show_streams "$TMP_DIR/$MP3_NAME" >/dev/null 2>&1; then
            need_mp3=false
        else
            log "⚠️ Existing $MP3_NAME is invalid, will re-encode"
            rm -f "$TMP_DIR/$MP3_NAME"
        fi
    elif has_remote_file "$VIDEO_ID" "$MP3_NAME"; then
        need_mp3=false
    fi

    if [ "$need_mp3" = true ]; then
        if [ "$HAS_AUDIO" -gt 0 ]; then
            log "🎧 Encoding podcast MP3"
            emit_pipeline_event "$VIDEO_ID" "podcast_mp3" "active" "start"
            ffmpeg -hide_banner -y -i "$INPUT_PATH" \
                -vn -map 0:a:0 -c:a libmp3lame -b:a 192k -f mp3 "$TMP_DIR/$MP3_NAME.tmp.$$"
            mv "$TMP_DIR/$MP3_NAME.tmp.$$" "$TMP_DIR/$MP3_NAME"
            log "✅ MP3 encoding done"
            emit_pipeline_event "$VIDEO_ID" "podcast_mp3" "active" "done"
        else
            log "⚠️ No audio stream for $VIDEO_ID — skipping MP3 generation"
            emit_pipeline_event "$VIDEO_ID" "podcast_mp3" "active" "skipped_no_audio"
        fi
    else
        log "⏩ Skipping MP3 encoding (already exists)"
        emit_pipeline_event "$VIDEO_ID" "podcast_mp3" "active" "skipped_existing"
    fi

    if [ "$should_process_video" = "1" ]; then
        need_package=true
        if [ -f "$TMP_DIR/master.m3u8" ]; then
            if [ -s "$TMP_DIR/master.m3u8" ] && [ -s "$TMP_DIR/manifest.mpd" ]; then
                need_package=false
            else
                log "⚠️ Existing manifests are invalid, will re-package"
                rm -f "$TMP_DIR/master.m3u8" "$TMP_DIR/manifest.mpd"
            fi
        fi

        if [ "$need_package" = true ]; then
            log "🚀 Packaging with Shaka"
            emit_pipeline_event "$VIDEO_ID" "package_hls" "active" "start"

            SHAKA_CMD=(shaka-packager
                "input=$TMP_DIR/1080p.mp4,stream=video,init_segment=$TMP_DIR/init_1080.mp4,segment_template=$TMP_DIR/seg_1080_\$Number\$.m4s"
                "input=$TMP_DIR/720p.mp4,stream=video,init_segment=$TMP_DIR/init_720.mp4,segment_template=$TMP_DIR/seg_720_\$Number\$.m4s"
                "input=$TMP_DIR/480p.mp4,stream=video,init_segment=$TMP_DIR/init_480.mp4,segment_template=$TMP_DIR/seg_480_\$Number\$.m4s"
                --segment_duration 2
                --fragment_duration 2
                --generate_static_live_mpd
                --mpd_output "$TMP_DIR/manifest.mpd"
                --hls_master_playlist_output "$TMP_DIR/master.m3u8"
            )

            [ "$HAS_AUDIO" -gt 0 ] && \
                SHAKA_CMD+=("input=$TMP_DIR/1080p.mp4,stream=audio,init_segment=$TMP_DIR/init_audio.mp4,segment_template=$TMP_DIR/seg_audio_\$Number\$.m4s")

            shaka_ok=false
            for i in {1..3}; do
                if "${SHAKA_CMD[@]}"; then
                    log "✅ Packaging done"
                    shaka_ok=true
                    emit_pipeline_event "$VIDEO_ID" "package_hls" "active" "done"
                    break
                else
                    log "⚠️ Shaka failed (attempt $i)"
                    emit_pipeline_event "$VIDEO_ID" "package_hls" "active" "retry_${i}"
                    sleep 2
                fi
            done
            if [ "$shaka_ok" != true ]; then
                log "❌ Packaging failed after 3 attempts for $VIDEO_ID"
                emit_pipeline_event "$VIDEO_ID" "failed" "failed" "packaging_failed"
                rm -f "$LOCK"
                release_slot "$BASHPID"
                return
            fi
        else
            log "⏩ Skipping packaging (already done)"
            emit_pipeline_event "$VIDEO_ID" "package_hls" "active" "skipped_existing"
        fi
    fi

    log "🚀 [$VIDEO_ID] Uploading to R2"
    emit_pipeline_event "$VIDEO_ID" "upload_assets" "active" "start"

UPLOAD_OK=false

for i in {1..5}; do
    emit_pipeline_event "$VIDEO_ID" "upload_assets" "active" "attempt_${i}/5"
    if ! rclone copy "$TMP_DIR" "${R2_BUCKET}:/videos/${VIDEO_ID}" \
        --exclude "1080p.mp4" \
        --exclude "720p.mp4" \
        --exclude "480p.mp4" \
        --ignore-existing \
        --transfers 8 \
        --checkers 16; then
        log "⚠️ [$VIDEO_ID] Upload attempt $i failed (rclone error)"
        sleep 3
        continue
    fi

    if ! REMOTE=$(rclone lsf "${R2_BUCKET}:/videos/${VIDEO_ID}" --recursive 2>/dev/null); then
        log "⚠️ [$VIDEO_ID] Upload attempt $i: rclone lsf failed — retrying upload"
        sleep 3
        continue
    fi
    MISSING=""
    REMOTE_BASENAMES=$(echo "$REMOTE" | awk -F/ '{print $NF}')

    if [ "$should_process_video" = "1" ]; then
        for required in master.m3u8 init_1080.mp4 init_720.mp4 init_480.mp4; do
            echo "$REMOTE_BASENAMES" | grep -qx "$required" || MISSING="$MISSING $required"
        done
        if [ "$HAS_AUDIO" -gt 0 ]; then
            echo "$REMOTE_BASENAMES" | grep -qx "init_audio.mp4" || MISSING="$MISSING init_audio.mp4"
            audio_seg_cnt=$(echo "$REMOTE_BASENAMES" | grep -c "^seg_audio_.*\\.m4s$" || true)
            [ "${audio_seg_cnt:-0}" -gt 0 ] || MISSING="$MISSING seg_audio_*.m4s(none)"
        fi

        for res in 1080 720 480; do
            cnt=$(echo "$REMOTE_BASENAMES" | grep -c "^seg_${res}_.*\\.m4s$" || true)
            [ "${cnt:-0}" -gt 0 ] || MISSING="$MISSING seg_${res}_*.m4s(none)"
        done
    fi

    if [ "$HAS_AUDIO" -gt 0 ]; then
        echo "$REMOTE_BASENAMES" | grep -qx "$MP3_NAME" || MISSING="$MISSING $MP3_NAME"
    fi

    if [ -z "$MISSING" ]; then
        UPLOAD_OK=true
        break
    else
        log "⚠️ [$VIDEO_ID] Upload attempt $i incomplete — missing:$MISSING"
        sleep 3
    fi
done

if [ "$UPLOAD_OK" = false ]; then
    log "❌ [$VIDEO_ID] Upload failed permanently — will retry later"
    emit_pipeline_event "$VIDEO_ID" "failed" "failed" "upload_failed"
    rm -f "$LOCK"
    release_slot "$BASHPID"
    return
fi

log "✅ Upload verified"
emit_pipeline_event "$VIDEO_ID" "upload_assets" "active" "verified"

if [ "$PREVIEW_MP3_ENABLED" = "1" ] && [ "$HAS_AUDIO" -gt 0 ]; then
    if [ ! -f "$TMP_DIR/$MP3_NAME" ]; then
        log "📥 Local MP3 missing, attempting to fetch from R2 for preview"
        if rclone copy "${R2_BUCKET}:/videos/${VIDEO_ID}/${MP3_NAME}" "$TMP_DIR/" 2>/dev/null; then
            log "✅ Fetched MP3 from R2 for preview rendering"
        else
            log "⚠️ Could not fetch MP3 from R2 — skipping preview"
            emit_pipeline_event "$VIDEO_ID" "preview_render" "active" "skipped"
            rm -f "$TMP_DIR/$MP3_NAME"
        fi
    fi

    if [ -f "$TMP_DIR/$MP3_NAME" ]; then
        emit_pipeline_event "$VIDEO_ID" "preview_wait" "active" "${PREVIEW_MP3_LOCK_SECONDS}s"
        sleep "$PREVIEW_MP3_LOCK_SECONDS"
        emit_pipeline_event "$VIDEO_ID" "preview_render" "active" "${PREVIEW_MP3_SECONDS}s"
        ffmpeg -hide_banner -y -i "$TMP_DIR/$MP3_NAME" -t "$PREVIEW_MP3_SECONDS" -vn -c:a libmp3lame -q:a 2 -f mp3 "$TMP_DIR/$MP3_PREVIEW_NAME.tmp.$$"
        mv "$TMP_DIR/$MP3_PREVIEW_NAME.tmp.$$" "$TMP_DIR/$MP3_PREVIEW_NAME"
        emit_pipeline_event "$VIDEO_ID" "preview_upload" "active" "start"
        rclone copyto "$TMP_DIR/$MP3_PREVIEW_NAME" "${R2_BUCKET}:/videos/${VIDEO_ID}/${MP3_PREVIEW_NAME}"
        emit_pipeline_event "$VIDEO_ID" "preview_upload" "active" "done"
    fi
else
    emit_pipeline_event "$VIDEO_ID" "preview_render" "active" "skipped"
fi

log "🧹 Cleaning up local files"
emit_pipeline_event "$VIDEO_ID" "cleanup" "active" "start"

touch "$DONE"

rm -f "$INPUT_PATH"
rm -rf "$TMP_DIR"

rm -f "$LOCK"
release_slot "$BASHPID"

log "🎉 Finished $VIDEO_ID"
local inbox_exists=false
for ext in mp4 mkv mov; do
    [ -f "$INBOX_DIR/${VIDEO_ID}.${ext}" ] && { inbox_exists=true; break; }
done
if [ "$inbox_exists" = false ] && [ ! -d "$TMP_DIR_BASE/$VIDEO_ID" ]; then
    emit_pipeline_event "$VIDEO_ID" "done" "success" "watchfolder_and_tmp_cleared"
else
    emit_pipeline_event "$VIDEO_ID" "failed" "failed" "cleanup_incomplete"
fi
}

enqueue_backfill_jobs_from_r2() {
    [ "$BACKFILL_FROM_R2" = "1" ] || return

    log "☁️  Scanning R2 for videos missing $MP3_NAME"
    local prefixes
    if ! prefixes=$(rclone lsf "${R2_BUCKET}:/videos" 2>/dev/null); then
        log "⚠️ Could not list R2 videos prefix; skipping backfill scan"
        return
    fi

    while IFS= read -r prefix; do
        [ -n "$prefix" ] || continue
        [[ "$prefix" =~ /$ ]] || continue
        local VIDEO_ID
        VIDEO_ID="${prefix%/}"
        [ -n "$VIDEO_ID" ] || continue

        if has_remote_file "$VIDEO_ID" "$MP3_NAME"; then
            continue
        fi

        local INPUT_PATH="$BACKFILL_STAGING_DIR/${VIDEO_ID}.mp4"
        process_video "$VIDEO_ID" "$INPUT_PATH" "backfill" || {
            log "⚠️ Backfill processing failed for $VIDEO_ID, continuing scan"
        }
    done <<< "$prefixes"
}

garbage_collect() {
    log "🗑️  Garbage collecting stale pipeline directories..."
    local had_any=false

    for dir in "$TMP_DIR_BASE"/*/; do
        [ -d "$dir" ] || continue
        had_any=true
        local VIDEO_ID
        VIDEO_ID=$(basename "$dir")
        local LOCK="$dir/.lock"
        local DONE="$dir/.done"

        if [ -f "$LOCK" ] && ! pgrep -f "process_video.*$VIDEO_ID" > /dev/null; then
            log "🗑️  GC: removing stale lock for $VIDEO_ID"
            rm -f "$LOCK"
        fi

        local inbox_exists=false
        for ext in mp4 mkv mov; do
            [ -f "$INBOX_DIR/${VIDEO_ID}.${ext}" ] && { inbox_exists=true; break; }
        done

        if [ -f "$DONE" ]; then
            log "🗑️  GC: removing completed tmp dir for $VIDEO_ID"
            for ext in mp4 mkv mov; do
                rm -f "$INBOX_DIR/${VIDEO_ID}.${ext}"
            done
            rm -rf "$dir"
        elif [ "$inbox_exists" = false ] && [ ! -f "$LOCK" ]; then
            log "🗑️  GC: removing orphaned tmp dir for $VIDEO_ID"
            rm -rf "$dir"
        fi
    done

    if [ "$had_any" = false ]; then
        log "🗑️  GC: nothing to clean up"
    fi
}

garbage_collect

log "🔍 Resuming existing jobs..."

for f in "$INBOX_DIR"/*; do
    [ -f "$f" ] || continue
    FILE=$(basename "$f")
    FILE_LOWER="${FILE,,}"
    [[ "$FILE_LOWER" =~ \.(mp4|mkv|mov)$ ]] || continue
    VIDEO_ID="${FILE%.*}"

    process_video "$VIDEO_ID" "$f" "startup_scan" &
done

garbage_collect

log "🎬 Watching for new uploads..."

enqueue_backfill_jobs_from_r2 &

inotifywait -m -e close_write --format "%f" "$INBOX_DIR" | while IFS= read -r FILE; do
    FILE_LOWER="${FILE,,}"
    [[ "$FILE_LOWER" =~ \.(mp4|mkv|mov)$ ]] || continue
    VIDEO_ID="${FILE%.*}"

    process_video "$VIDEO_ID" "$INBOX_DIR/$FILE" "watchfolder" &
done

wait